import { Parameter, ParameterValue, Tool, Command } from "@/commandly/types/flat";
import { getCommandPath } from "@/commandly/utils/flat";
import { Button } from "@/components/ui/button";
import { TerminalIcon, CopyIcon, SaveIcon } from "lucide-react";
import { useCallback, useEffect, useState, useMemo } from "react";
import { toast } from "sonner";

interface GeneratedCommandProps {
  tool: Tool;
  selectedCommand?: Command;
  parameterValues: Record<string, ParameterValue>;
  onSaveCommand?: (command: string) => void;
}

export function GeneratedCommand({
  tool,
  selectedCommand,
  parameterValues,
  onSaveCommand,
}: GeneratedCommandProps) {
  selectedCommand = selectedCommand || tool.commands[0];
  const [generatedCommand, setGeneratedCommand] = useState("");

  const globalParameters = useMemo(() => {
    return tool.parameters?.filter((p) => p.isGlobal) || [];
  }, [tool]);

  const currentParameters = useMemo(() => {
    return tool?.parameters?.filter((p) => p.commandKey === selectedCommand?.key) || [];
  }, [tool, selectedCommand]);

  const generateCommand = useCallback(() => {
    if (!selectedCommand) return;
    const commandPath = getCommandPath(selectedCommand, tool);
    let command = tool.name == commandPath ? tool.name : `${tool.name} ${commandPath}`;

    const parametersWithValues: Array<{
      param: Parameter;
      value: ParameterValue;
    }> = [];

    globalParameters.forEach((param) => {
      const value = parameterValues[param.key];
      if (value !== undefined && value !== "" && value !== false) {
        parametersWithValues.push({ param, value });
      }
    });

    currentParameters.forEach((param) => {
      const value = parameterValues[param.key];
      if (value !== undefined && value !== "" && value !== false && !param.isGlobal) {
        parametersWithValues.push({ param, value });
      }
    });

    const positionalParams = parametersWithValues
      .filter(({ param }) => param.parameterType === "Argument")
      .sort((a, b) => (a.param.position || 0) - (b.param.position || 0));

    parametersWithValues.forEach(({ param, value }) => {
      if (param.parameterType === "Flag") {
        if (value === true) {
          const flag = param.shortFlag || param.longFlag;
          if (flag) command += ` ${flag}`;
        }
      } else if (param.parameterType === "Option") {
        const flag = param.shortFlag || param.longFlag;
        if (flag) {
          const separator = param.keyValueSeparator ?? " ";
          command += ` ${flag}${separator}${value}`;
        }
      } else if (param.parameterType === "Argument") {
        command += ` ${value}`;
      }
    });

    positionalParams.forEach(({ value }) => {
      command += ` ${value}`;
    });

    setGeneratedCommand(command);
  }, [tool, parameterValues, selectedCommand, globalParameters, currentParameters]);

  useEffect(() => {
    generateCommand();
  }, [generateCommand]);

  const copyCommand = () => {
    navigator.clipboard.writeText(generatedCommand);
    toast("Command copied!");
  };

  return (
    <div>
      {tool.commands.length === 0 ? (
        <div className="py-8 text-center">
          <TerminalIcon className="mx-auto mb-4 h-12 w-12 text-muted-foreground" />
          <p className="text-muted-foreground">No commands available for this tool.</p>
        </div>
      ) : generatedCommand ? (
        <div className="space-y-4">
          <div className="rounded bg-muted p-4 font-mono text-sm">{generatedCommand}</div>
          <div className="flex gap-2">
            <Button
              onClick={copyCommand}
              variant="outline"
              className="flex-1"
            >
              <CopyIcon className="mr-2 h-4 w-4" />
              Copy Command
            </Button>
            {onSaveCommand && (
              <Button
                onClick={() => onSaveCommand(generatedCommand)}
                variant="outline"
                className="flex-1"
              >
                <SaveIcon className="mr-2 h-4 w-4" />
                Save Command
              </Button>
            )}
          </div>
        </div>
      ) : (
        <div className="py-8 text-center">
          <TerminalIcon className="mx-auto mb-4 h-12 w-12 text-muted-foreground" />
          <p className="text-muted-foreground">Configure parameters to generate the command.</p>
        </div>
      )}
    </div>
  );
}

import { Tool } from "@/commandly/types/flat";
import { exportToStructuredJSON } from "@/commandly/utils/flat";
import { convertToNestedStructure } from "@/commandly/utils/nested";
import { Button } from "@/components/ui/button";
import { Card, CardAction, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Command as UICommand,
  CommandGroup,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";
import { CheckIcon, ChevronsUpDownIcon, CopyIcon, Edit2Icon, XIcon } from "lucide-react";
import { useEffect, useState } from "react";
import { toast } from "sonner";

const jsonOptions = [
  { value: "nested", label: "Nested" },
  { value: "flat", label: "Flat" },
];

interface JsonTypeComponentProps {
  tool: Tool;
  onApply?: (tool: Tool) => void;
}

export function JsonOutput({ tool, onApply }: JsonTypeComponentProps) {
  const [open, setOpen] = useState(false);
  const [jsonString, setJsonString] = useState<string>();
  const [jsonType, setJsonType] = useState<"nested" | "flat">("flat");
  const [isEditing, setIsEditing] = useState(false);
  const [editValue, setEditValue] = useState("");

  useEffect(() => {
    const config =
      jsonType === "flat" ? exportToStructuredJSON(tool) : convertToNestedStructure(tool);
    setJsonString(JSON.stringify(config, null, 2));
  }, [jsonType, tool]);

  const handleEditToggle = () => {
    setEditValue(jsonString ?? "");
    setIsEditing(true);
  };

  const handleApply = () => {
    try {
      const parsed = JSON.parse(editValue) as Tool;
      onApply!(parsed);
      setIsEditing(false);
    } catch {
      toast.error("Invalid JSON", { description: "Please fix the JSON before applying." });
    }
  };

  const handleCancel = () => {
    setIsEditing(false);
    setEditValue("");
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle>
          <span className="text-sm">Output type: </span>
          <Popover
            open={open}
            onOpenChange={setOpen}
          >
            <PopoverTrigger asChild>
              <Button
                variant="outline"
                role="combobox"
                aria-expanded={open}
                className="w-48 justify-between"
              >
                {jsonOptions.find((option) => option.value === jsonType)?.label}
                <ChevronsUpDownIcon className="opacity-50" />
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-48 p-0">
              <UICommand>
                <CommandList>
                  <CommandGroup>
                    {jsonOptions.map((option) => (
                      <CommandItem
                        key={option.value}
                        value={option.value}
                        onSelect={(currentValue) => {
                          setJsonType(currentValue as "nested" | "flat");
                          setOpen(false);
                        }}
                      >
                        {option.label}
                        <CheckIcon
                          className={cn(
                            "ml-auto h-4 w-4",
                            jsonType === option.value ? "opacity-100" : "opacity-0",
                          )}
                        />
                      </CommandItem>
                    ))}
                  </CommandGroup>
                </CommandList>
              </UICommand>
            </PopoverContent>
          </Popover>
        </CardTitle>
        <div className="flex gap-3">
          {onApply && !isEditing && (
            <CardAction
              className="rounded-md"
              onClick={handleEditToggle}
            >
              <Edit2Icon className="h-4 w-4 dark:stroke-primary" />
            </CardAction>
          )}
          {onApply && isEditing && (
            <CardAction
              className="rounded-md"
              onClick={handleCancel}
            >
              <XIcon className="h-4 w-4 dark:stroke-primary" />
            </CardAction>
          )}
          <CardAction
            className="rounded-md"
            onClick={() => {
              navigator.clipboard.writeText(jsonString!);
              toast("Copied!");
            }}
          >
            <CopyIcon className="h-4 w-4 dark:stroke-primary" />
          </CardAction>
        </div>
      </CardHeader>
      <CardContent>
        {isEditing ? (
          <div className="flex flex-col gap-2">
            <ScrollArea
              className="max-w-full *:data-radix-scroll-area-viewport:max-h-[calc(100vh-360px)]"
              type="hover"
            >
              <Textarea
                className="min-h-[calc(100vh-400px)] font-mono text-sm"
                value={editValue}
                onChange={(e) => setEditValue(e.target.value)}
                spellCheck={false}
              />
              <ScrollBar orientation="vertical" />
              <ScrollBar orientation="horizontal" />
            </ScrollArea>
            <div className="flex justify-end gap-2">
              <Button
                variant="outline"
                size="sm"
                onClick={handleCancel}
              >
                Cancel
              </Button>
              <Button
                size="sm"
                onClick={handleApply}
              >
                Apply
              </Button>
            </div>
          </div>
        ) : (
          <ScrollArea
            className="max-w-full *:data-radix-scroll-area-viewport:max-h-[calc(100vh-320px)]"
            type="hover"
          >
            <pre className="max-h max-w-full rounded-md bg-card font-mono text-sm dark:text-gray-200">
              {jsonString}
            </pre>
            <ScrollBar orientation="vertical" />
            <ScrollBar orientation="horizontal" />
          </ScrollArea>
        )}
      </CardContent>
    </Card>
  );
}

import { ParameterValue } from "@/commandly/types/flat";
import { Command, Tool } from "@/commandly/types/flat";
import { ParameterRenderContext, ParameterRendererEntry } from "@/commandly/types/renderer";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { InfoIcon } from "lucide-react";
import React from "react";

const findDefaultCommand = (tool: Tool): Command | null => {
  const defaultCommand = tool.commands.find((command) => command.isDefault);
  if (defaultCommand) return defaultCommand;

  const nameMatchCommand = tool.commands.find(
    (command) => command.name.toLowerCase() === tool.name.toLowerCase(),
  );
  if (nameMatchCommand) return nameMatchCommand;

  return tool.commands.length > 0 ? tool.commands[0] : null;
};

interface ParameterLabelProps {
  name: string;
  longFlag?: string;
  shortFlag?: string;
  isRequired?: boolean;
  isGlobal?: boolean;
  description?: string;
  className?: string;
  children?: React.ReactNode;
}

function ParameterLabel({
  name,
  longFlag,
  shortFlag,
  isRequired,
  isGlobal,
  description,
  className,
  children,
}: ParameterLabelProps) {
  return (
    <Label className={className}>
      {name}
      {(longFlag || shortFlag) && (
        <span className="ml-1 text-muted-foreground">
          ({[longFlag, shortFlag].filter(Boolean).join(", ")})
        </span>
      )}
      {isRequired && <span className="ml-1 text-destructive">*</span>}
      <Tooltip>
        <TooltipTrigger>
          <InfoIcon className="h-3.5 w-3.5" />
        </TooltipTrigger>
        <TooltipContent>
          <span>{description}</span>
        </TooltipContent>
      </Tooltip>
      {children}
      {isGlobal && (
        <Badge
          variant="outline"
          className="ml-2 text-xs"
        >
          global
        </Badge>
      )}
    </Label>
  );
}

function FlagInput({ parameter, value, onUpdate }: ParameterRenderContext) {
  return (
    <div className="flex items-center space-x-2">
      <Switch
        checked={value === "true" || value === true}
        onCheckedChange={onUpdate}
      />
      <ParameterLabel
        className="flex-1 select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
    </div>
  );
}

function OptionEnumInput({ parameter, value, onUpdate }: ParameterRenderContext) {
  return (
    <div className="space-y-2">
      <ParameterLabel
        className="select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
      <Select
        value={value as string}
        onValueChange={onUpdate}
      >
        <SelectTrigger>
          <SelectValue placeholder="Select an option" />
        </SelectTrigger>
        <SelectContent>
          {parameter.enum?.values?.map((enumValue) => (
            <SelectItem
              key={enumValue.value}
              value={enumValue.value}
            >
              {enumValue.displayName || enumValue.value}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
    </div>
  );
}

function OptionBooleanInput({ parameter, value, onUpdate }: ParameterRenderContext) {
  return (
    <div className="flex items-center space-x-2">
      <Switch
        checked={value === "true" || value === true}
        onCheckedChange={(checked) => onUpdate(checked.toString())}
      />
      <ParameterLabel
        className="flex-1 select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
    </div>
  );
}

function OptionTextInput({ parameter, value, onUpdate }: ParameterRenderContext) {
  return (
    <div className="space-y-2">
      <ParameterLabel
        className="flex-1 select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
      <Input
        type={parameter.dataType === "Number" ? "number" : "text"}
        value={parameter.dataType === "Number" ? (value as number) : (value as string)}
        onChange={(e) => onUpdate(e.target.value)}
        placeholder="Enter value"
      />
    </div>
  );
}

function ArgumentInput({ parameter, value, onUpdate }: ParameterRenderContext) {
  return (
    <div className="space-y-2">
      <ParameterLabel
        name={parameter.name}
        isRequired={parameter.isRequired}
        description={parameter.description}
      >
        <Badge
          variant="secondary"
          className="ml-2 text-xs"
        >
          {parameter.parameterType}
          {parameter.position !== undefined && ` (${parameter.position})`}
        </Badge>
      </ParameterLabel>
      <Input
        type={parameter.dataType === "Number" ? "number" : "text"}
        value={parameter.dataType === "Number" ? (value as number) : (value as string)}
        onChange={(e) => onUpdate(e.target.value)}
        placeholder="Enter value"
      />
    </div>
  );
}

export function defaultComponents(): ParameterRendererEntry[] {
  return [
    { condition: (p) => p.parameterType === "Flag", component: (ctx) => <FlagInput {...ctx} /> },
    {
      condition: (p) => p.parameterType === "Argument",
      component: (ctx) => <ArgumentInput {...ctx} />,
    },
    {
      condition: (p) => p.parameterType === "Option" && p.dataType === "Enum",
      component: (ctx) => <OptionEnumInput {...ctx} />,
    },
    {
      condition: (p) => p.parameterType === "Option" && p.dataType === "Boolean",
      component: (ctx) => <OptionBooleanInput {...ctx} />,
    },
    {
      condition: (p) => p.parameterType === "Option",
      component: (ctx) => <OptionTextInput {...ctx} />,
    },
  ];
}

interface ToolRendererProps {
  selectedCommand?: Command | null;
  tool: Tool;
  catalog?: ParameterRendererEntry[];
  parameterValues: Record<string, ParameterValue>;
  updateParameterValue: (parameterKey: string, value: ParameterValue) => void;
}

export function ToolRenderer({
  selectedCommand: providedCommand,
  tool,
  catalog = defaultComponents(),
  parameterValues,
  updateParameterValue,
}: ToolRendererProps) {
  const selectedCommand = providedCommand ?? findDefaultCommand(tool);

  return (
    <React.Fragment>
      {selectedCommand && tool.commands.length === 0 ? (
        <p className="text-sm text-muted-foreground">No commands available for this tool.</p>
      ) : (
        <div className="space-y-4">
          {tool.parameters.length > 0 ? (
            tool.parameters
              .filter((param) => param.commandKey === selectedCommand?.key || param.isGlobal)
              .map((parameter) => {
                const value = parameterValues[parameter.key] || "";
                const onUpdate = (val: ParameterValue) => updateParameterValue(parameter.key, val);
                const entry = catalog.find((e) => e.condition(parameter));
                return entry ? (
                  <React.Fragment key={parameter.key}>
                    {entry.component({ parameter, value, onUpdate })}
                  </React.Fragment>
                ) : null;
              })
          ) : (
            <p className="text-sm text-muted-foreground">
              No parameters available for this command.
            </p>
          )}
        </div>
      )}
    </React.Fragment>
  );
}

import type { Parameter, ParameterValue } from "@/commandly/types/flat";
import type { ReactElement } from "react";

export type ParameterRenderContext = {
  parameter: Parameter;
  value: ParameterValue;
  onUpdate: (value: ParameterValue) => void;
};

export type ParameterRendererEntry = {
  condition: (parameter: Parameter) => boolean;
  component: (context: ParameterRenderContext) => ReactElement | null;
};

export interface ToolInfo {
  description?: string;
  version?: string;
  url?: string;
}

export interface Command {
  key: string;
  parentCommandKey?: string;
  name: string;
  description?: string;
  interactive?: boolean;
  isDefault?: boolean;
  sortOrder?: number;
}

export interface ParameterEnumValue {
  value: string;
  displayName: string;
  description?: string;
  isDefault?: boolean;
  sortOrder?: number;
}

export interface ParameterEnumValues {
  values: ParameterEnumValue[];
  allowMultiple?: boolean;
  separator?: string;
}

export type ParameterValidationType =
  | "min_length"
  | "max_length"
  | "min_value"
  | "max_value"
  | "regex";

export interface ParameterValidation {
  key: string;
  validationType: ParameterValidationType;
  validationValue: string;
  errorMessage: string;
}

export type ParameterDependencyType = "requires" | "conflicts_with";

export interface ParameterDependency {
  key: string;
  parameterKey: string;
  dependsOnParameterKey: string;
  dependencyType: ParameterDependencyType;
  conditionValue?: string;
}

export type ParameterValue = string | number | boolean;

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface ToolMetadata {}

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface ParameterMetadata {
  tags?: string[];
}

export type ParameterType = "Flag" | "Option" | "Argument";

export type ParameterDataType = "String" | "Number" | "Boolean" | "Enum";

export interface Parameter {
  key: string;
  name: string;
  commandKey?: string;
  description?: string;
  group?: string;
  metadata?: ParameterMetadata;
  parameterType: ParameterType;
  dataType: ParameterDataType;
  isRequired?: boolean;
  isRepeatable?: boolean;
  isGlobal?: boolean;
  shortFlag?: string;
  longFlag?: string;
  position?: number;
  sortOrder?: number;
  arraySeparator?: string;
  keyValueSeparator?: string;
  enum?: ParameterEnumValues;
  validations?: ParameterValidation[];
  dependencies?: ParameterDependency[];
}

export type ExclusionType = "mutual_exclusive" | "required_one_of";

export interface ExclusionGroup {
  key?: string;
  commandKey?: string;
  name: string;
  exclusionType: ExclusionType;
  parameterKeys: string[];
}

export interface Tool {
  name: string;
  displayName: string;
  info?: ToolInfo;
  commands: Command[];
  parameters: Parameter[];
  exclusionGroups?: ExclusionGroup[];
  metadata?: ToolMetadata;
}

import type {
  ExclusionType,
  ParameterDataType,
  ParameterDependencyType,
  ParameterEnumValues,
  ParameterMetadata,
  ParameterType,
  ParameterValidationType,
  ToolInfo,
  ToolMetadata,
} from "@/commandly/types/flat";

export interface NestedParameterValidation {
  validationType: ParameterValidationType;
  validationValue: string;
  errorMessage: string;
}

export interface NestedParameterDependency {
  dependsOnParameter: string;
  dependencyType: ParameterDependencyType;
  conditionValue?: string;
}

export interface NestedParameter {
  name: string;
  description?: string;
  group?: string;
  parameterType: ParameterType;
  dataType: ParameterDataType;
  metadata?: ParameterMetadata;
  isRequired?: boolean;
  isRepeatable?: boolean;
  isGlobal?: boolean;
  shortFlag?: string;
  longFlag?: string;
  position?: number;
  sortOrder?: number;
  arraySeparator?: string;
  keyValueSeparator?: string;
  enum?: ParameterEnumValues;
  validations?: NestedParameterValidation[];
  dependencies?: NestedParameterDependency[];
}

export interface NestedCommand {
  name: string;
  description?: string;
  interactive?: boolean;
  isDefault: boolean;
  sortOrder: number;
  parameters: NestedParameter[];
  subcommands: NestedCommand[];
}

export interface NestedExclusionGroup {
  name: string;
  exclusionType: ExclusionType;
  parameters: string[];
}

export interface NestedTool {
  $schema?: string;
  name: string;
  displayName: string;
  info?: ToolInfo;
  url?: string;
  globalParameters: NestedParameter[];
  commands: NestedCommand[];
  exclusionGroups?: NestedExclusionGroup[] | null;
  metadata?: ToolMetadata;
}

import type { Command, ExclusionGroup, Parameter, Tool } from "@/commandly/types/flat";

export const buildCommandHierarchy = (commands: Command[]): Command[] => {
  return commands.sort(
    (a, b) => (a.sortOrder ?? commands.indexOf(a)) - (b.sortOrder ?? commands.indexOf(b)),
  );
};

export const slugify = (text: string): string => {
  return text
    .toString()
    .toLowerCase()
    .trim()
    .replace(/\s+/g, "-") // Replace spaces with -
    .replace(/[^\w-]+/g, "") // Remove all non-word chars
    .replace(/--+/g, "-") // Replace multiple - with single -
    .replace(/^-+/, "") // Trim - from start of text
    .replace(/-+$/, ""); // Trim - from end of text
};

export const getCommandPath = (command: Command, tool: Tool): string => {
  const findCommandPath = (
    targetKey: string,
    commands: Command[],
    path: string[] = [],
  ): string[] | null => {
    for (const cmd of commands) {
      if (cmd.name === targetKey) {
        return [...path, cmd.name];
      }

      const childCommands = commands.filter((c) => c.parentCommandKey === cmd.key);
      if (childCommands.length > 0) {
        const subPath = findCommandPath(targetKey, childCommands, [...path, cmd.name]);
        if (subPath) {
          return subPath;
        }
      }
    }
    return null;
  };

  const rootCommands = tool.commands.filter((c) => !c.parentCommandKey);
  const path = findCommandPath(command.name, rootCommands);

  if (!path) return command.name;

  if (command.name === tool.name && command.isDefault) {
    return tool.name;
  }

  const rootCommand = tool.commands.find((c) => c.name === tool.name);
  if (rootCommand?.isDefault && path[0] === tool.name) {
    path[0] = tool.name;
  }

  return path.join(" ");
};

export const getAllSubcommands = (commandKey: string, commands: Command[]): Command[] => {
  const result: Command[] = [];

  const findSubcommands = (parentKey: string) => {
    commands.forEach((cmd) => {
      if (cmd.parentCommandKey === parentKey) {
        result.push(cmd);
        findSubcommands(cmd.key);
      }
    });
  };

  findSubcommands(commandKey);
  return result;
};

const SCHEMA_URL = "https://commandly.divyeshio.in/specification/flat.json";

export const sanitizeToolJSON = (tool: Record<string, unknown>): Record<string, unknown> => {
  const parameters = Array.isArray(tool.parameters)
    ? (tool.parameters as Record<string, unknown>[]).map(
        ({ metadata: _metadata, ...param }) => param,
      )
    : tool.parameters;

  return {
    $schema: SCHEMA_URL,
    ...tool,
    parameters,
  };
};

export const exportToStructuredJSON = (tool: Tool) => {
  return {
    $schema: SCHEMA_URL,
    name: tool.name,
    displayName: tool.displayName,
    info: tool.info,
    url: tool.info?.url,
    commands: tool.commands.map((cmd) => ({ ...cmd })),
    parameters: tool.parameters.map(({ metadata: _metadata, ...param }) => param),
    exclusionGroups: tool.exclusionGroups,
    metadata: tool.metadata,
  };
};

export const flattenImportedData = (importedData: Record<string, unknown>): Tool => {
  const {
    name,
    displayName,
    commands = [],
    exclusionGroups = [],
    metadata = {
      supportedInput: [],
      supportedOutput: [],
    },
  } = importedData as {
    name: string;
    displayName?: string;
    parameters?: Parameter[];
    commands?: Record<string, unknown>[];
    exclusionGroups?: ExclusionGroup[];
    metadata?: Tool["metadata"];
  };

  const allParameters: Parameter[] = [];

  const flattenCommandParameters = (
    command: Record<string, unknown>,
    parentKey?: string,
  ): Command[] => {
    const {
      parameters = [],
      subcommands = [],
      ...commandData
    } = command as {
      parameters?: Parameter[];
      subcommands?: Record<string, unknown>[];
      [key: string]: unknown;
    };

    (parameters as Parameter[]).forEach((param: Parameter) => {
      allParameters.push({
        ...param,
        commandKey: command.key as string,
        ...(!command.name ? { isGlobal: true } : {}),
      });
    });

    const flatCommand: Command = {
      ...commandData,
      parentCommandKey: parentKey,
    } as Command;

    const flatCommands = [flatCommand];

    (subcommands as Record<string, unknown>[]).forEach((subcmd) => {
      flatCommands.push(...flattenCommandParameters(subcmd, command.key as string));
    });

    return flatCommands;
  };

  const flatCommands: Command[] = [];
  (commands as Record<string, unknown>[]).forEach((cmd) => {
    flatCommands.push(...flattenCommandParameters(cmd));
  });

  return {
    name: name,
    displayName: displayName || name,
    info: importedData.info as Tool["info"] | undefined,
    commands: flatCommands,
    parameters: allParameters,
    exclusionGroups,
    metadata,
  };
};

export const validateDefaultValue = (
  parameter: Parameter,
): { isValid: boolean; error?: string } => {
  void parameter;
  return { isValid: true };
};

export const createNewCommand = (parentKey?: string): Command => {
  const name = randomCommandName();
  return {
    key: slugify(name),
    parentCommandKey: parentKey,
    name,
    isDefault: false,
    sortOrder: 1,
  };
};

export const createNewParameter = (isGlobal: boolean, commandKey?: string): Parameter => {
  return {
    key: "",
    name: "",
    commandKey: isGlobal ? undefined : commandKey,
    parameterType: "Option",
    dataType: "String",
    ...(isGlobal ? { isGlobal: true } : {}),
    longFlag: "",
  };
};

export const randomCommandName = () => {
  const characters = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
  let result = "";
  const charactersLength = characters.length;
  for (let i = 0; i < 7; i++) {
    result += characters.charAt(Math.floor(Math.random() * charactersLength));
  }
  return result;
};

export function generateHashCode(s: string): string {
  let h = 0;
  for (let i = 0; i < s.length; i++) h = (Math.imul(31, h) + s.charCodeAt(i)) | 0;

  return h.toString();
}

const isEmpty = (value: unknown[] | Record<string, unknown> | null | undefined): boolean => {
  if (value == null) return true;
  if (Array.isArray(value)) return value.length === 0;
  return Object.keys(value).length === 0;
};

const cleanParameter = (param: Parameter): Parameter => {
  const cleaned = { ...param };

  if (!cleaned.enum || cleaned.enum.values.length === 0) delete cleaned.enum;
  if (isEmpty(cleaned.validations)) delete cleaned.validations;
  if (isEmpty(cleaned.dependencies)) delete cleaned.dependencies;

  if (cleaned.metadata) {
    const meta = { ...cleaned.metadata };
    if (isEmpty(meta.tags)) delete meta.tags;
    if (isEmpty(meta as Record<string, unknown>)) {
      delete cleaned.metadata;
    } else {
      cleaned.metadata = meta;
    }
  }

  return cleaned;
};

export const cleanupTool = (tool: Tool): Tool => {
  const cleaned = { ...tool };

  if (isEmpty(cleaned.exclusionGroups)) delete cleaned.exclusionGroups;
  if (isEmpty(cleaned.metadata as Record<string, unknown> | null | undefined))
    delete cleaned.metadata;

  cleaned.parameters = cleaned.parameters.map(cleanParameter);

  return cleaned;
};

import type { Tool, Command, Parameter } from "@/commandly/types/flat";
import {
  NestedCommand,
  NestedExclusionGroup,
  NestedParameter,
  NestedTool,
} from "@/commandly/types/nested";

export const convertToNestedStructure = (tool: Tool): NestedTool => {
  const globalParameters = tool.parameters.filter((p) => p.isGlobal);

  const convertParameter = (param: Parameter): NestedParameter => {
    const { ...rest } = param;
    return {
      ...rest,
      validations: param.validations?.map((v) => {
        return {
          validationType: v.validationType,
          validationValue: v.validationValue,
          errorMessage: v.errorMessage,
        };
      }),
      metadata: param.metadata,
      dataType: param.dataType,
      dependencies: param.dependencies?.map((dep) => {
        const dependsOnParam = tool.parameters.find((p) => p.key === dep.dependsOnParameterKey);
        return {
          dependsOnParameter: dependsOnParam?.longFlag || "",
          dependencyType: dep.dependencyType,
          conditionValue: dep.conditionValue,
        };
      }),
    };
  };

  const buildNestedCommands = (commands: Command[], parentKey?: string): NestedCommand[] => {
    return commands
      .filter((cmd) => cmd.parentCommandKey === parentKey)
      .map((cmd) => {
        const commandParameters = tool.parameters.filter(
          (p) => p.commandKey === cmd.key && !p.isGlobal,
        );
        return {
          name: cmd.name,
          description: cmd.description,
          interactive: cmd.interactive,
          isDefault: cmd.isDefault ?? false,
          sortOrder: cmd.sortOrder ?? 0,
          parameters: commandParameters.map(convertParameter),
          subcommands: buildNestedCommands(commands, cmd.key),
        };
      });
  };

  const nestedExclusionGroups: NestedExclusionGroup[] | undefined = tool.exclusionGroups?.map(
    (group) => {
      return {
        name: group.name,
        exclusionType: group.exclusionType,
        parameters: group.parameterKeys.map((pk) => {
          const param = tool.parameters.find((p) => p.key === pk);
          return param?.longFlag || "";
        }),
      };
    },
  );

  return {
    $schema: "https://commandly.divyeshio.in/specification/nested.json",
    name: tool.name,
    url: tool.info?.url,
    displayName: tool.displayName,
    info: tool.info,
    metadata: tool.metadata,
    globalParameters: globalParameters.map(convertParameter),
    commands: buildNestedCommands(tool.commands),
    exclusionGroups: nestedExclusionGroups,
  };
};
